// Package policy defines the SPI for the policy engine.
//
// The policy engine is the decision-making core of the control plane. It
// receives a normalized intent and returns a disposition: allow, deny,
// require approval, or request more evidence. All other components in the
// control plane consume this decision.
//
// The built-in implementation evaluates rule sets stored in the database.
// Alternative implementations (OPA, Cedar, custom DSLs) satisfy this
// interface without modifying the core.
package policy

import "context"

// Engine evaluates whether an intent should be allowed, denied, or escalated.
type Engine interface {
	Evaluate(ctx context.Context, req EvaluationRequest) (Decision, error)
}

// EvaluationRequest is the input to policy evaluation.
type EvaluationRequest struct {
	WorkspaceID string
	AgentID     string
	Action      Action
	Context     IntentContext
}

// Action describes what the agent intends to do.
type Action struct {
	// Type is a dot-namespaced action identifier, e.g. "payment.charge",
	// "git.pull_request.create", "calendar.event.create".
	Type          string
	Summary       string
	Justification string
	Target        ActionTarget
	Domain        DomainPayload
}

// ActionTarget describes the resource the action operates on.
type ActionTarget struct {
	Kind        string
	ID          string
	DisplayName string
}

// DomainPayload carries action-type-specific fields.
// Only the field corresponding to Action.Type will be populated.
type DomainPayload struct {
	Payment  *PaymentPayload
	Git      *GitPayload
	Calendar *CalendarPayload
}

// PaymentPayload carries payment-specific intent fields.
type PaymentPayload struct {
	VendorName    string
	VendorID      string
	AmountMinor   int64
	Currency      string
	Category      string
	BudgetCode    string
	FundingSource string
}

// GitPayload carries git-specific intent fields.
type GitPayload struct {
	Provider   string
	Repository string
	Branch     string
	BaseBranch string
	PRTitle    string
}

// CalendarPayload carries calendar-specific intent fields.
type CalendarPayload struct {
	Provider string
	Title    string
	// Attendee email addresses.
	Attendees []string
}

// IntentContext carries runtime context used by policy rules.
type IntentContext struct {
	Environment     string
	SourcePlatform  string
	SourceSessionID string
	IPAddress       string
	UserPresent     bool
	RiskHints       []string
}

// Decision is the output of policy evaluation.
type Decision struct {
	Disposition     Disposition
	RiskLevel       RiskLevel
	MatchedPolicies []PolicyMatch
	DenialReason    string
}

// PolicyMatch records which policy rule produced the decision.
type PolicyMatch struct {
	PolicyID      string
	PolicyVersion int
	RuleID        string
	Explanation   string
}

// Disposition is the outcome of policy evaluation.
type Disposition string

const (
	DispositionAllow               Disposition = "allow"
	DispositionAllowModified       Disposition = "allow_modified"
	DispositionRequireApproval     Disposition = "require_approval"
	DispositionDeny                Disposition = "deny"
	DispositionRequireMoreEvidence Disposition = "require_more_evidence"
)

// RiskLevel is the assessed risk of the intent.
type RiskLevel string

const (
	RiskLevelLow      RiskLevel = "low"
	RiskLevelMedium   RiskLevel = "medium"
	RiskLevelHigh     RiskLevel = "high"
	RiskLevelCritical RiskLevel = "critical"
)

// Package approval defines the SPI for the approval orchestrator.
//
// The approval orchestrator manages the human-in-the-loop lifecycle:
// routing approval requests to the right people, tracking their responses,
// handling expiry, and issuing execution grants when approval is granted.
//
// The built-in implementation persists approvals in the database and
// dispatches notifications via the notify.Notifier SPI. Alternative
// implementations can integrate with external workflow systems.
package approval

import (
	"context"
	"time"
)

// Orchestrator manages the lifecycle of approval requests.
type Orchestrator interface {
	// Request creates a new approval request for the given intent.
	Request(ctx context.Context, req ApprovalRequest) (Approval, error)

	// Get returns an approval by ID.
	Get(ctx context.Context, approvalID string) (Approval, error)

	// Approve records an approval decision and issues an execution grant.
	Approve(ctx context.Context, approvalID string, req ApproveRequest) (Approval, error)

	// Deny records a denial and closes the intent.
	Deny(ctx context.Context, approvalID string, req DenyRequest) (Approval, error)

	// Modify approves with parameter constraints, bounding what the agent
	// may execute.
	Modify(ctx context.Context, approvalID string, req ModifyRequest) (Approval, error)

	// List returns pending approvals, optionally filtered by assignee.
	List(ctx context.Context, filter ListFilter) ([]Approval, error)
}

// ApprovalRequest is the input for creating a new approval.
type ApprovalRequest struct {
	IntentID    string
	WorkspaceID string
	// Rationale is the human-readable reason approval is required.
	Rationale string
	// Approvers is the list of principals who may act on this request.
	Approvers []ApproverRef
	ExpiresAt *time.Time
	// EditableBounds describes which parameters an approver may modify.
	EditableBounds map[string]any
}

// ApproverRef identifies a principal who may approve or deny.
type ApproverRef struct {
	PrincipalID string
	DisplayName string
	Role        string
}

// Approval is the full approval record.
type Approval struct {
	ApprovalID     string
	IntentID       string
	WorkspaceID    string
	Status         Status
	Rationale      string
	Approvers      []ApproverActor
	EditableBounds map[string]any
	ExpiresAt      *time.Time
	RequestedAt    time.Time
	ResolvedAt     *time.Time
}

// ApproverActor is an approver with their individual status.
type ApproverActor struct {
	PrincipalID string
	DisplayName string
	Role        string
	Status      ActorStatus
}

// Status is the overall state of an approval request.
type Status string

const (
	StatusPending   Status = "pending"
	StatusApproved  Status = "approved"
	StatusDenied    Status = "denied"
	StatusModified  Status = "modified"
	StatusDelegated Status = "delegated"
	StatusExpired   Status = "expired"
	StatusCancelled Status = "cancelled"
)

// ActorStatus is an individual approver's response.
type ActorStatus string

const (
	ActorStatusPending   ActorStatus = "pending"
	ActorStatusApproved  ActorStatus = "approved"
	ActorStatusDenied    ActorStatus = "denied"
	ActorStatusDelegated ActorStatus = "delegated"
)

// ApproveRequest is the input for an approval decision.
type ApproveRequest struct {
	Comment           string
	ApproveOnce       bool
	StepUpAuthAssertion string
}

// DenyRequest is the input for a denial decision.
type DenyRequest struct {
	Reason  string
	Comment string
}

// ModifyRequest approves with bounded parameter constraints.
type ModifyRequest struct {
	Comment       string
	Modifications map[string]any
}

// ListFilter scopes an approval list query.
type ListFilter struct {
	WorkspaceID string
	Assignee    string
	Status      Status
	PageSize    int
	PageToken   string
}

// Package main is the entry point for the Aileron control plane server.
//
// The server wires together the core components — policy engine, approval
// orchestrator, connector registry, vault, notifiers, and audit store —
// and exposes the control plane API over HTTP.
package main

import (
	"context"
	"fmt"
	"log/slog"
	"net/http"
	"os"
	"os/signal"
	"syscall"
	"time"

	"github.com/ALRubinger/aileron/core/connector"
	googlecalendar "github.com/ALRubinger/aileron/core/connector/calendar/google"
	"github.com/ALRubinger/aileron/core/connector/git/github"
	"github.com/ALRubinger/aileron/core/connector/payments/stripe"
)

func main() {
	log := slog.New(slog.NewJSONHandler(os.Stdout, nil))

	if err := run(log); err != nil {
		log.Error("server exited with error", "error", err)
		os.Exit(1)
	}
}

func run(log *slog.Logger) error {
	cfg := configFromEnv()

	// --- Connector registry ---
	registry := connector.NewRegistry()
	registry.Register(stripe.New())
	registry.Register(googlecalendar.New())
	registry.Register(github.New())

	// --- HTTP server ---
	mux := http.NewServeMux()
	registerRoutes(mux, log, registry)

	srv := &http.Server{
		Addr:         cfg.addr,
		Handler:      mux,
		ReadTimeout:  10 * time.Second,
		WriteTimeout: 30 * time.Second,
		IdleTimeout:  120 * time.Second,
	}

	// Graceful shutdown on SIGINT / SIGTERM.
	ctx, stop := signal.NotifyContext(context.Background(), syscall.SIGINT, syscall.SIGTERM)
	defer stop()

	go func() {
		log.Info("server listening", "addr", cfg.addr)
		if err := srv.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			log.Error("listen error", "error", err)
		}
	}()

	<-ctx.Done()
	log.Info("shutting down")

	shutdownCtx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
	defer cancel()

	return srv.Shutdown(shutdownCtx)
}

func registerRoutes(mux *http.ServeMux, log *slog.Logger, _ *connector.Registry) {
	// Health check — no auth required.
	mux.HandleFunc("GET /v1/health", handleHealth(log))

	// TODO: register intent, approval, policy, connector, execution,
	// funding source, credential, trace, and analytics handlers.
}

func handleHealth(log *slog.Logger) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		log.InfoContext(r.Context(), "health check")
		w.Header().Set("Content-Type", "application/json")
		fmt.Fprintf(w, `{"status":"ok","service":"aileron","version":"0.1.0"}`)
	}
}

// config holds runtime configuration sourced from environment variables.
type config struct {
	addr        string
	databaseURL string
}

func configFromEnv() config {
	addr := os.Getenv("AILERON_ADDR")
	if addr == "" {
		addr = ":8080"
	}
	return config{
		addr:        addr,
		databaseURL: os.Getenv("DATABASE_URL"),
	}
}

// Package connector defines the SPI for execution connectors.
//
// A connector bridges the control plane to an external system — a payment
// processor, a git provider, a calendar service, etc. When the policy engine
// allows an action (or a human approves it), the control plane selects the
// appropriate connector and calls Execute.
//
// Each connector implementation is responsible for one external system.
// The SPI is intentionally narrow: connectors receive a bounded execution
// request and return a result. Credential injection and parameter bounding
// happen in the control plane before the connector is called.
package connector

import "context"

// Connector executes an approved action against an external system.
type Connector interface {
	// Type returns the connector type identifier (e.g. "payments", "git",
	// "calendar"). Used by the registry to route execution requests.
	Type() string

	// Provider returns the specific provider name (e.g. "stripe", "github",
	// "google_calendar"). Multiple connectors may share a Type.
	Provider() string

	// Execute runs the action described by the request.
	Execute(ctx context.Context, req ExecutionRequest) (ExecutionResult, error)
}

// ExecutionRequest is passed to a connector when executing an approved action.
type ExecutionRequest struct {
	GrantID     string
	IntentID    string
	ConnectorID string
	// ActionType is the dot-namespaced action, e.g. "payment.charge".
	ActionType string
	// Parameters are the bounded, approved parameters for execution.
	// These are constrained by the execution grant and may differ from
	// the original intent if a human modified them during approval.
	Parameters map[string]any
	// Credential is the injected secret for this connector, resolved from
	// the vault. Connectors must not store or log this value.
	Credential *InjectedCredential
}

// InjectedCredential carries a resolved secret for use during execution.
// Connectors receive this transiently and must not persist it.
type InjectedCredential struct {
	Type  string
	Value []byte
}

// ExecutionResult is returned by a connector after execution.
type ExecutionResult struct {
	Status     ExecutionStatus
	Output     map[string]any
	ReceiptRef string
	Error      string
}

// ExecutionStatus is the outcome of a connector execution.
type ExecutionStatus string

const (
	ExecutionStatusSucceeded ExecutionStatus = "succeeded"
	ExecutionStatusFailed    ExecutionStatus = "failed"
	ExecutionStatusCancelled ExecutionStatus = "cancelled"
)

// Registry holds the registered connectors and routes execution requests.
type Registry struct {
	connectors map[string]Connector
}

// NewRegistry returns an empty connector registry.
func NewRegistry() *Registry {
	return &Registry{connectors: make(map[string]Connector)}
}

// Register adds a connector to the registry.
// The key is "<type>/<provider>", e.g. "payments/stripe".
func (r *Registry) Register(c Connector) {
	key := c.Type() + "/" + c.Provider()
	r.connectors[key] = c
}

// Get returns the connector for the given type and provider.
func (r *Registry) Get(connectorType, provider string) (Connector, bool) {
	c, ok := r.connectors[connectorType+"/"+provider]
	return c, ok
}

// Package vault defines the SPI for credential and secret storage.
//
// The vault stores sensitive values (API keys, OAuth tokens, service account
// credentials) and injects them into connector execution requests without
// ever exposing them to agents. Agents see only a credential reference ID;
// the vault resolves the actual secret at execution time.
//
// The built-in implementation encrypts secrets at rest using AES-GCM with
// a key stored in the environment. Alternative implementations can delegate
// to HashiCorp Vault, AWS Secrets Manager, GCP Secret Manager, etc.
package vault

import "context"

// Vault stores and retrieves secrets by path.
type Vault interface {
	// Get retrieves a secret by its vault path.
	Get(ctx context.Context, path string) (Secret, error)

	// Put stores a secret at the given path, creating or overwriting it.
	Put(ctx context.Context, path string, value []byte, meta Metadata) error

	// Delete permanently removes a secret.
	Delete(ctx context.Context, path string) error
}

// Secret is a resolved secret value.
type Secret struct {
	Path     string
	Value    []byte
	Metadata Metadata
}

// Metadata carries non-secret attributes stored alongside a secret.
type Metadata struct {
	// Type classifies the credential (e.g. "api_key", "oauth_refresh_token").
	Type        string
	Environment string
	// Labels are arbitrary key-value pairs for organization.
	Labels map[string]string
}

