// Package notify defines the SPI for human approval notifications.
//
// When an intent requires human approval, the approval orchestrator
// dispatches a notification via this SPI. The notification includes a
// deep link back to the web app where the approver can review and act.
//
// The built-in implementations deliver via Slack and email. Alternative
// implementations can target other channels (PagerDuty, SMS, Teams, etc.)
// without modifying the orchestrator.
package notify

import "context"

// Notifier delivers approval request notifications to human approvers.
type Notifier interface {
	// Notify sends an approval request notification to the listed approvers.
	Notify(ctx context.Context, n Notification) error
}

// Notification is the data delivered to approvers when an approval is needed.
type Notification struct {
	ApprovalID  string
	IntentID    string
	WorkspaceID string
	// Summary is a one-line human-readable description of what the agent
	// wants to do, drawn from the intent.
	Summary string
	// ReviewURL is the deep link to the approval UI for this request.
	ReviewURL string
	// Approvers are the people who should receive this notification.
	Approvers []Approver
}

// Approver is a person who should be notified about an approval request.
type Approver struct {
	PrincipalID string
	DisplayName string
	// Contact is the channel-specific address (email address, Slack user ID).
	Contact string
}

// Multi dispatches a notification to multiple notifiers in sequence.
// Errors from individual notifiers are collected but do not stop delivery
// to subsequent notifiers.
type Multi struct {
	notifiers []Notifier
}

// NewMulti returns a Notifier that dispatches to all provided notifiers.
func NewMulti(notifiers ...Notifier) *Multi {
	return &Multi{notifiers: notifiers}
}

// Notify dispatches the notification to all registered notifiers.
func (m *Multi) Notify(ctx context.Context, n Notification) error {
	var errs []error
	for _, notifier := range m.notifiers {
		if err := notifier.Notify(ctx, n); err != nil {
			errs = append(errs, err)
		}
	}
	if len(errs) > 0 {
		return &MultiError{Errors: errs}
	}
	return nil
}

// MultiError collects errors from multiple notifiers.
type MultiError struct {
	Errors []error
}

func (e *MultiError) Error() string {
	msg := "notification errors:"
	for _, err := range e.Errors {
		msg += " " + err.Error() + ";"
	}
	return msg
}

// Package audit defines the SPI for the immutable audit/trace store.
//
// Every significant event in the control plane lifecycle — intent submission,
// policy decision, approval action, execution outcome — is recorded as an
// append-only trace event. This provides a verifiable audit trail for
// compliance, debugging, and trust.
//
// The built-in implementation writes to a Postgres append-only table.
// Alternative implementations can target immutable object storage, a
// dedicated audit log service, or a blockchain-backed store.
package audit

import (
	"context"
	"time"
)

// Store records and retrieves immutable trace events.
type Store interface {
	// Append records a new event. Implementations must treat this as
	// append-only: existing events must never be modified or deleted.
	Append(ctx context.Context, event Event) error

	// ListTraces returns traces matching the filter.
	ListTraces(ctx context.Context, filter Filter) ([]Trace, error)

	// GetTrace returns the full trace for a given intent.
	GetTrace(ctx context.Context, traceID string) (Trace, error)
}

// Event is a single immutable audit record.
type Event struct {
	EventID   string
	EventType EventType
	Actor     ActorRef
	// Payload carries event-specific data. Must be serialisable to JSON.
	Payload   map[string]any
	Timestamp time.Time
}

// ActorRef identifies who or what produced the event.
type ActorRef struct {
	ID          string
	Type        ActorType
	DisplayName string
}

// ActorType classifies the event producer.
type ActorType string

const (
	ActorTypeAgent            ActorType = "agent"
	ActorTypeHuman            ActorType = "human"
	ActorTypeService          ActorType = "service"
	ActorTypeConnectorRuntime ActorType = "connector_runtime"
)

// EventType identifies the kind of event.
type EventType string

const (
	EventTypeIntentSubmitted    EventType = "intent.submitted"
	EventTypePolicyEvaluated    EventType = "policy.evaluated"
	EventTypeApprovalRequested  EventType = "approval.requested"
	EventTypeApprovalApproved   EventType = "approval.approved"
	EventTypeApprovalDenied     EventType = "approval.denied"
	EventTypeApprovalModified   EventType = "approval.modified"
	EventTypeGrantIssued        EventType = "grant.issued"
	EventTypeGrantRevoked       EventType = "grant.revoked"
	EventTypeExecutionStarted   EventType = "execution.started"
	EventTypeExecutionSucceeded EventType = "execution.succeeded"
	EventTypeExecutionFailed    EventType = "execution.failed"
)

// Trace is the full ordered event history for one intent.
type Trace struct {
	TraceID     string
	IntentID    string
	WorkspaceID string
	Events      []Event
}

// Filter scopes a trace list query.
type Filter struct {
	WorkspaceID string
	IntentID    string
	ActorID     string
	EventType   EventType
	From        *time.Time
	To          *time.Time
	PageSize    int
	PageToken   string
}

// Package stripe implements the payments connector for Stripe.
//
// This connector executes payment.charge actions via the Stripe API using
// Stripe Issuing virtual cards. Credentials are injected at execution time
// from the vault and are never stored by this package.
package stripe

import (
	"context"
	"errors"

	"github.com/ALRubinger/aileron/core/connector"
)

const (
	connectorType     = "payments"
	connectorProvider = "stripe"
)

// Connector executes payment actions via Stripe.
type Connector struct{}

// New returns a new Stripe payments connector.
func New() *Connector {
	return &Connector{}
}

// Type implements connector.Connector.
func (c *Connector) Type() string { return connectorType }

// Provider implements connector.Connector.
func (c *Connector) Provider() string { return connectorProvider }

// Execute implements connector.Connector.
func (c *Connector) Execute(ctx context.Context, req connector.ExecutionRequest) (connector.ExecutionResult, error) {
	if req.Credential == nil {
		return connector.ExecutionResult{}, errors.New("stripe: no credential injected")
	}

	switch req.ActionType {
	case "payment.charge":
		return c.charge(ctx, req)
	default:
		return connector.ExecutionResult{
			Status: connector.ExecutionStatusFailed,
			Error:  "stripe: unsupported action type: " + req.ActionType,
		}, nil
	}
}

func (c *Connector) charge(_ context.Context, req connector.ExecutionRequest) (connector.ExecutionResult, error) {
	// TODO: implement Stripe Issuing virtual card charge via Stripe API.
	// Steps:
	//   1. Resolve funding source to a Stripe Issuing cardholder / card pool.
	//   2. Create an ephemeral virtual card scoped to the approved parameters.
	//   3. Initiate the charge.
	//   4. Return the Stripe charge ID as ReceiptRef.
	_ = req
	return connector.ExecutionResult{}, errors.New("stripe: charge not yet implemented")
}

